FINAL_ANSWER: import sys

def solve():
    input_data = sys.stdin.read().split()
    if not input_data: return
    N, M, K = map(int, input_data[:3])
    idx = 3
    board = []
    for _ in range(9):
        board.append(list(map(int, input_data[idx:idx+9])))
        idx += 9
    stamps = []
    for _ in range(M):
        stamp = []
        for _ in range(3):
            stamp.append(list(map(int, input_data[idx:idx+3])))
            idx += 3
        stamps.append(stamp)

    MOD = 998244353
    placements = []

    for _ in range(K):
        best_gain = 0
        best_move = None

        for m_idx in range(M):
            stamp = stamps[m_idx]
            for i in range(7):
                for j in range(7):
                    current_gain = 0
                    for r in range(3):
                        for c in range(3):
                            old_val = board[i+r][j+c]
                            new_val = (old_val + stamp[r][c]) % MOD
                            current_gain += (new_val - old_val)

                    if current_gain > best_gain:
                        best_gain = current_gain
                        best_move = (m_idx, i, j)

        if best_move:
            m_idx, i, j = best_move
            placements.append(f"{m_idx} {i} {j}")
            stamp = stamps[m_idx]
            for r in range(3):
                for c in range(3):
                    board[i+r][j+c] = (board[i+r][j+c] + stamp[r][c]) % MOD
        else:
            break

    print(len(placements))
    for p in placements:
        print(p)

solve()

JUSTIFICATION: Python code implements greedy stamp placement maximizing sum increase.
